# Script to evaluate the answers generated by different LLMs
from clusterAnswers import execEvalOfQuestions,applyBootstrapping
import promptLLM as promptLLM
from CONFIG import ANSWER_CLUSTER_FOLDER

FILE_LIST = [
    "EVAL_Image_Acquisition_GPT4o.csv",
    "EVAL_Image_Acquisition_LLAMA3.1_70B.csv",
    "EVAL_Image_Acquisition_LLAMA3.1_8B.csv",
    
    "EVAL_Guidelines_and_Indications_GPT4o.csv",
    "EVAL_Guidelines_and_Indications_LLAMA3.1_70B.csv",
    "EVAL_Guidelines_and_Indications_LLAMA3.1_8B.csv",

    "EVAL_Imaging_Education_GPT4o.csv",
    "EVAL_Imaging_Education_LLAMA3.1_70B.csv",
    "EVAL_Imaging_Education_LLAMA3.1_8B.csv",

    "EVAL_Research_GPT4o.csv",
    "EVAL_Research_LLAMA3.1_70B.csv",
    "EVAL_Research_LLAMA3.1_8B.csv",
]

O1_LIST = [
    "EVAL_Image_Acquisition_o1_unknownTemperature.csv",
    "EVAL_Guidelines_and_Indications_o1_unknownTemperature.csv",
    "EVAL_Imaging_Education_o1_unknownTemperature.csv",
    "EVAL_Research_prompt_o1_unknownTemperature.csv",
]

GPT4_LIST = [
    "EVAL_Image_Acquisition_GPT4o.csv",
    "EVAL_Guidelines_and_Indications_GPT4o.csv",
    "EVAL_Imaging_Education_GPT4o.csv",
    "EVAL_Research_GPT4o.csv",
]

LLAMA_70B_LIST = [
    "EVAL_Image_Acquisition_LLAMA3.1_70B.csv",
    "EVAL_Guidelines_and_Indications_LLAMA3.1_70B.csv",
    "EVAL_Imaging_Education_LLAMA3.1_70B.csv",
    "EVAL_Research_LLAMA3.1_70B.csv",

]

LLAMA_8B_LIST = [
    "EVAL_Image_Acquisition_LLAMA3.1_8B.csv",
    "EVAL_Guidelines_and_Indications_LLAMA3.1_8B.csv",
    "EVAL_Imaging_Education_LLAMA3.1_8B.csv",
    "EVAL_Research_LLAMA3.1_8B.csv",
]

TOPIC_LIST = [FILE_LIST[0:3]] + [FILE_LIST[3:6]] + [FILE_LIST[6:9]] + [FILE_LIST[9:12]]

# The function addFolder appends a path prefix to each file
addFolder = lambda lst: [ANSWER_CLUSTER_FOLDER + x for x in lst]

# Evaluate O1 model outputs using GPT4o for entailment checks
o1ClusterAnswerList = execEvalOfQuestions(addFolder(O1_LIST),promptFunc=promptLLM.promptGPT4o)# change new prompt parameter when done

for file in O1_LIST:
    execEvalOfQuestions(addFolder([file]),promptFunc=promptLLM.promptGPT4o)

# Evaluate other model outputs similarly
o1ClusterAnswerList = execEvalOfQuestions(addFolder(O1_LIST),promptFunc=promptLLM.promptGPT4o)# change new prompt parameter when done

gpt4oClusterAnswerList = execEvalOfQuestions(addFolder(GPT4_LIST),promptFunc=promptLLM.promptGPT4o)

llama70bClusterAnswerList = execEvalOfQuestions(addFolder(LLAMA_70B_LIST),promptFunc=promptLLM.promptGPT4o)

llama8bClusterAnswerList = execEvalOfQuestions(addFolder(LLAMA_8B_LIST),promptFunc=promptLLM.promptGPT4o)

print("bootstrapping evaluation")
print("Accuracy gain for using semantic entropy:")

# Apply bootstrap analysis to calculate confidence intervals for the accuracy gain
print("o1")
applyBootstrapping(o1ClusterAnswerList,confP=0.05/4)
print("")

print("GPT4o")
applyBootstrapping(gpt4oClusterAnswerList,confP=0.05/4)
print("")

print("LLAMA 3.1 70B")
applyBootstrapping(llama70bClusterAnswerList,confP=0.05/4)
print("")

print("LLAMA 3.1 8B")
applyBootstrapping(llama8bClusterAnswerList,confP=0.05/4)
print("")

for file in FILE_LIST:
    execEvalOfQuestions(addFolder([file]),promptFunc=promptLLM.promptGPT4o)

print("+++")

for topic in TOPIC_LIST:
    execEvalOfQuestions(addFolder(topic),promptFunc=promptLLM.promptGPT4o)
